function highestScoreDivisions(nums) {
    let count0 = 0, count1 = 0;
    for (let n of nums) {
        if (n === 1) count1++;
    }

    let maxScore = -1, currentScore = 0;
    let result = [];
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] === 0) {
            currentScore++;
        } else {
            count1--;
        }

        if (currentScore > maxScore) {
            maxScore = currentScore;
            result = [i];
        } else if (currentScore === maxScore) {
            result.push(i);
        }
    }
    return result;
}
```


